INSERT INTO gg_courses (slug, name, tagline, designer, year_opened, par, yardage, slope_rating, course_rating, course_type, address, city, phone, green_fee_min, green_fee_max, season, difficulty, elevation_ft, distance_from_graeagle, description, signature_hole, highlights, faq_items, speakable_summary, meta_title, meta_description, is_active, content_status, sort_order)
VALUES

('graeagle-meadows', 'Graeagle Meadows Golf Course', 'The Classic Sierra Valley Course', 'Ellis Van Gorder', 1968, 72, 6759, 120, 70.7, 'Public', '6934 CA-89', 'Graeagle', '(530) 836-2323', 45, 99, 'April–November', 'Beginner-Friendly', 3500, '0 min', 'Graeagle Meadows is the original Sierra golf experience — a welcoming, fair layout winding through towering pines alongside the middle fork of the Feather River. Opened in 1968 and designed by Ellis Van Gorder, it plays 6,759 yards from the tips at par 72. The course is known for panoramic views of the Mohawk Valley, a modest slope of 120, and a forgiving design that rewards accurate iron play over raw power. Golf Digest has recognized it as one of the Best Places to Play in California.', 'Hole #16 — 170-yard par-3 framed by towering pines, playing down a hallway of trees to a green guarded by three bunkers.', '["Panoramic views of Mohawk Valley","Along the middle fork of Feather River","Golf Digest Best Places to Play","Signature hole #6 with valley views","Driving range with 5 practice tees","Full restaurant, bar & pro shop"]'::jsonb, '[{"question":"Is Graeagle Meadows good for high handicappers?","answer":"Yes. With a slope of 120 and a forgiving layout, Graeagle Meadows is one of the most beginner-friendly courses in the Sierra Nevada."},{"question":"Does Graeagle Meadows have a restaurant?","answer":"Yes. The clubhouse features a full restaurant serving breakfast, lunch and dinner, plus a fully stocked pro shop and bar."},{"question":"How far is Graeagle Meadows from Lake Tahoe?","answer":"Approximately 47 miles north of Lake Tahoe via Highway 89 — about a 50-minute drive."}]'::jsonb, 'Graeagle Meadows Golf Course is an 18-hole par-72 public course in Graeagle, California, designed by Ellis Van Gorder and opened in 1968. It plays 6,759 yards with a slope of 120 and a course rating of 70.7.', 'Graeagle Meadows | Par 72, 6,759 Yards | Sierra Golf', 'Graeagle Meadows Golf Course — par 72, 6,759 yards, slope 120, designed by Ellis Van Gorder (1968). Public. Golf Digest Best Places to Play. Green fees $45–$99.', true, 'complete', 1),

('whitehawk-ranch', 'Whitehawk Ranch Golf Club', 'The Undiscovered Gem of the Sierra', 'Dick Bailey', 1996, 71, 6983, 132, 72.3, 'Public', '768 Whitehawk Dr', 'Clio', '(530) 836-0394', 99, 149, 'May–October', 'Intermediate–Advanced', 4200, '10 min', 'Whitehawk Ranch is widely regarded as the crown jewel of the Graeagle area. Designed by Dick Bailey and opened in 1996 on nearly 1,000 acres of former cattle ranch land, the course takes players through three breathtaking environments — open meadow, dense forest, and creekside finisher. Golf Digest panelists have called it "without question, an undiscovered gem in California." Seven streams meander through pines, cedars, firs, and quaking aspens.', 'Hole #18 — A par-5 finisher that plays through trees, along a river, then over a creek to the green. One of the most dramatic finishing holes in Northern California.', '["Golf Digest panelist-rated 4.2/5","Carved from a 1,000-acre cattle ranch","Native grasses, wildflowers, 7 streams & ponds","Three terrain types: meadow, forest, creekside","Complete practice facility","Par-71 with nearly 7,000 yards"]'::jsonb, '[{"question":"What makes Whitehawk Ranch special?","answer":"Whitehawk Ranch is carved from a 1,000-acre former cattle ranch, with seven streams, native wildflowers, and three distinct terrain types. Golf Digest rated it 4.2/5 and called it an undiscovered gem."},{"question":"How difficult is Whitehawk Ranch?","answer":"With a slope of 132 and course rating of 72.3, Whitehawk plays harder than it looks. Its par-71 layout requires all clubs in the bag."},{"question":"Does Whitehawk Ranch have a practice facility?","answer":"Yes — one of the best in the Sierra, with a full driving range, chipping area, sand trap practice, and putting green."}]'::jsonb, 'Whitehawk Ranch Golf Club is an 18-hole par-71 public course in Clio, California, designed by Dick Bailey and opened in 1996. It plays 6,983 yards with a slope of 132 on 1,000 acres of former cattle ranch land.', 'Whitehawk Ranch | Golf Digest Gem | Clio CA', 'Whitehawk Ranch Golf Club — par 71, 6,983 yards, slope 132. Golf Digest 4.2/5. Carved from 1,000-acre Sierra ranch. Green fees $99–$149.', true, 'complete', 2),

('plumas-pines', 'Plumas Pines Golf Resort', 'Augusta Slope. Sierra Soul.', 'Homer Flint', 1980, 72, 6504, 132, 71.3, 'Public', '402 Poplar Valley Rd', 'Blairsden', '(530) 836-1420', 99, 139, 'April–November', 'Intermediate–Advanced', 3700, '5 min', 'Plumas Pines Golf Resort carries a slope rating of 132 from just 6,504 yards — the same difficulty rating once attributed to Augusta National. Designed by Homer Flint in 1980, the course follows the Middle Fork of the Feather River through lush alpine meadow. Narrow fairways, challenging greens, and water in play throughout reward precision over power. Longboards Bar & Grill inside the lodge is one of the best restaurants in the Graeagle area.', 'The opening stretch — holes 1–4 feature some of the most scenic and well-designed holes in the Sierra, playing alongside the river with stunning mountain backdrops.', '["Slope 132 on 6,504 yards — same as Augusta National","Follows Middle Fork Feather River","Longboards Bar & Grill on site","Lost Sierra Play Both Pass with Grizzly Ranch ($250)","Tournament play available"]'::jsonb, '[{"question":"Why does Plumas Pines have such a high slope rating?","answer":"Plumas Pines carries a slope of 132 despite playing only 6,504 yards. Narrow fairways, water throughout, and challenging greens create far more difficulty than the yardage suggests."},{"question":"What is the Lost Sierra Play Both Pass?","answer":"The Lost Sierra Play Both Pass ($250) gives you one round at Plumas Pines and one at Grizzly Ranch — two of the best courses in the region at a significant discount."},{"question":"Is there a restaurant at Plumas Pines?","answer":"Yes — Longboards Bar & Grill inside the resort lodge is widely considered one of the top dining spots in the Graeagle area."}]'::jsonb, 'Plumas Pines Golf Resort is an 18-hole par-72 public course in Blairsden, California, designed by Homer Flint and opened in 1980. It plays 6,504 yards with a slope of 132 along the Middle Fork of the Feather River.', 'Plumas Pines Golf Resort | Slope 132 | Blairsden CA', 'Plumas Pines Golf Resort — par 72, 6,504 yards, slope 132. Same difficulty as Augusta National. Longboards Bar & Grill on site. Green fees $99–$139.', true, 'complete', 3),

('grizzly-ranch', 'Grizzly Ranch Golf Club', 'Golf Digest Top 100. Sierra Nevada.', 'Bob Cupp', 2005, 72, 7411, 140, 74.9, 'Semi-Private', '250 Clubhouse Dr', 'Portola', '(530) 832-4200', 145, 175, 'April–November', 'Advanced', 5000, '20 min', 'Grizzly Ranch Golf Club is the marquee name in Graeagle-area golf — a Golf Digest Top 100 course set on the edge of the million-acre Plumas National Forest. Designed by Bob Cupp and opened in 2005, it stretches 7,411 yards with a slope of 140 and a course rating of 74.9. At elevations between 4,800 and 5,400 feet, golfers gain significant carry distance. The Lake House restaurant, with its sunken bar and open-air terrace overlooking the 18th green, is the best post-round destination in the region.', 'Hole #11 — A drivable par-4 at 267 yards, surrounded by bunkers, demanding a perfectly shaped tee shot. High risk, high reward.', '["Golf Digest Top 100 Courses nationally","#1 public course in the Sierras (Golf Digest 2014)","Ranked #53 in California (2025–26)","7,411 yards from the tips","Elevation 4,800–5,400 ft","Lake House restaurant overlooks 18th green"]'::jsonb, '[{"question":"Is Grizzly Ranch really a top 100 course?","answer":"Yes. Golf Digest ranks Grizzly Ranch in the Top 100 public courses in the US, and ranked it #1 in the Sierras in 2014. It is currently ranked 53rd in California as of 2025-26."},{"question":"Is Grizzly Ranch open to the public?","answer":"Yes. Grizzly Ranch is semi-private and open to daily fee players. It went public in 2012. Green fees range from $145–$175."},{"question":"How far is Grizzly Ranch from Graeagle?","answer":"Approximately 20 minutes from Graeagle, located in Portola along Highway 70 near Lake Davis."}]'::jsonb, 'Grizzly Ranch Golf Club is an 18-hole par-72 semi-private course in Portola, California, designed by Bob Cupp and opened in 2005. It stretches 7,411 yards with a slope of 140 and is ranked in Golf Digest Top 100.', 'Grizzly Ranch | Golf Digest Top 100 | Portola CA', 'Grizzly Ranch Golf Club — Golf Digest Top 100. Par 72, 7,411 yards, slope 140. Semi-private. Green fees $145–$175. 20 min from Graeagle.', true, 'complete', 4),

('nakoma-dragon', 'Nakoma — The Dragon', 'Frank Lloyd Wright. Robin Nelson. Pure Drama.', 'Robin Nelson & Neil Haworth', 1998, 72, 7015, 147, 73.4, 'Public/Resort', '348 Bear Run', 'Clio', '(530) 322-3333', 75, 135, 'May 1–October 31', 'Advanced–Expert', 4400, '15 min', 'The Dragon at Nakoma Resort is one of the most visually stunning and technically demanding courses in the country. Designed by Robin Nelson and opened in 1998, the Dragon earned immediate recognition as a Golf World Top 75 course. Its slope rating of 147 from the tips places it among the most challenging public courses in California. The 23,000 sq ft Frank Lloyd Wright-designed clubhouse is the only golf clubhouse in the world built by the legendary architect.', 'Hole #10 — An elevated par-4 tee shot drops dramatically to a green guarded by water. Picture-postcard views from every tee box.', '["Golf World Top 75 Courses in America","Only golf clubhouse designed by Frank Lloyd Wright","Slope 147 — most challenging in the region","Designed by Robin Nelson (Dunes at Mauna Lani)","5 tee sets: 4,611 to 7,015 yards","Golf Advisor Top 25 for Pace of Play"]'::jsonb, '[{"question":"Who designed the Nakoma clubhouse?","answer":"The 23,000 sq ft clubhouse at Nakoma was designed by Frank Lloyd Wright — making it the only golf clubhouse in the world designed by the legendary architect."},{"question":"How hard is the Dragon golf course?","answer":"The Dragon carries a slope of 147 from the tips — among the highest in California. Five tee sets play from 4,611 to 7,015 yards so all skill levels can play."},{"question":"When is Nakoma Golf Resort open?","answer":"The Dragon is open May 1 through October 31. Collared shirts required; no denim on course."}]'::jsonb, 'The Dragon at Nakoma Resort is an 18-hole par-72 resort course in Clio, California, designed by Robin Nelson and opened in 1998. It plays 7,015 yards with a slope of 147 and features the world''s only Frank Lloyd Wright-designed golf clubhouse.', 'Nakoma Dragon | Frank Lloyd Wright Clubhouse | Clio', 'Nakoma The Dragon Golf Course — Golf World Top 75. Par 72, slope 147. Only Frank Lloyd Wright golf clubhouse. Green fees $75–$135. Season May–Oct.', true, 'complete', 5);
